css:
* { margin: 0; padding: 0; box-sizing: border-box; }
body { font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', sans-serif; background: #030712; color: white; }
nav { display: flex; align-items: center; justify-content: space-between; padding: 0 80px; height: 72px; border-bottom: 1px solid rgba(255,255,255,0.07); }
.logo { font-size: 22px; font-weight: 800; }
.links { display: flex; gap: 28px; } .links a { color: #6b7280; text-decoration: none; font-weight: 500; font-size: 15px; }
.nav-actions { display: flex; gap: 12px; }
.login { padding: 10px 20px; border-radius: 10px; border: 1px solid rgba(255,255,255,0.12); background: transparent; color: white; font-weight: 600; cursor: pointer; }
.signup { padding: 10px 20px; border-radius: 10px; border: none; background: #3b82f6; color: white; font-weight: 700; cursor: pointer; }
.hero { display: grid; grid-template-columns: 1fr 1fr; gap: 60px; align-items: center; padding: 80px; min-height: calc(100vh - 72px); }
.badge { display: inline-flex; align-items: center; gap: 8px; padding: 8px 16px; border-radius: 20px; background: rgba(59,130,246,0.1); border: 1px solid rgba(59,130,246,0.25); color: #93c5fd; font-size: 13px; margin-bottom: 28px; } .badge a { color: #60a5fa; }
h1 { font-size: 64px; font-weight: 900; letter-spacing: -2.5px; line-height: 1; margin-bottom: 20px; }
.hero-content > p { color: #6b7280; font-size: 18px; line-height: 1.7; margin-bottom: 32px; max-width: 460px; }
.actions { display: flex; gap: 14px; margin-bottom: 40px; }
.btn-primary { padding: 15px 28px; border-radius: 12px; border: none; background: #3b82f6; color: white; font-weight: 700; font-size: 15px; cursor: pointer; }
.btn-ghost { padding: 15px 28px; border-radius: 12px; border: 1px solid rgba(255,255,255,0.15); background: transparent; color: white; font-weight: 600; font-size: 15px; cursor: pointer; }
.trust { display: flex; align-items: center; gap: 16px; color: #4b5563; font-size: 14px; } .trust strong { color: #9ca3af; font-weight: 700; }
.app-window { border-radius: 16px; border: 1px solid rgba(255,255,255,0.1); overflow: hidden; background: #0f172a; box-shadow: 0 40px 80px rgba(0,0,0,0.6); }
.window-bar { display: flex; align-items: center; padding: 12px 16px; background: rgba(255,255,255,0.04); border-bottom: 1px solid rgba(255,255,255,0.07); }
.w-dots { display: flex; gap: 6px; } .w-dots i { width: 10px; height: 10px; border-radius: 50%; background: rgba(255,255,255,0.15); display: block; }
.app-body { display: flex; height: 300px; }
.app-sidebar { width: 150px; background: rgba(255,255,255,0.03); border-right: 1px solid rgba(255,255,255,0.06); padding: 16px 10px; }
.menu-item { padding: 10px 12px; border-radius: 8px; font-size: 12px; color: #4b5563; margin-bottom: 4px; } .menu-item.active { background: rgba(59,130,246,0.15); color: #60a5fa; }
.app-main { flex: 1; padding: 20px; }
.app-header { font-size: 14px; font-weight: 700; margin-bottom: 16px; color: #e2e8f0; }
.app-charts { display: flex; align-items: flex-end; gap: 8px; height: 100px; margin-bottom: 20px; }
.chart-bar { flex: 1; border-radius: 4px; background: linear-gradient(180deg, #3b82f6, #1d4ed8); }
.app-stats { display: flex; gap: 12px; }
.app-stat { flex: 1; padding: 12px; border-radius: 8px; background: rgba(255,255,255,0.04); } .app-stat span { display: block; font-size: 10px; color: #6b7280; margin-bottom: 4px; } .app-stat strong { font-size: 18px; font-weight: 800; }
.features { padding: 80px; border-top: 1px solid rgba(255,255,255,0.07); }
.f-title { font-size: 36px; font-weight: 800; text-align: center; margin-bottom: 48px; }
.f-grid { display: grid; grid-template-columns: repeat(3, 1fr); gap: 20px; }
.f-card { padding: 28px; border-radius: 16px; background: rgba(255,255,255,0.03); border: 1px solid rgba(255,255,255,0.07); }
.f-icon { font-size: 28px; margin-bottom: 14px; } .f-card h3 { font-size: 16px; font-weight: 700; margin-bottom: 8px; } .f-card p { color: #6b7280; font-size: 14px; line-height: 1.6; }
